  ('P3', 'Four gate questions answered non-hand-wavily', 'BizModel §3', 'JUDGE', 'PRE', 'HARD', NULL, NULL, 'HARD - the four questions are the BizModel gate; hand-waving = redesign.', 2),
  ('P4', '''Too much'' guard — scale-infra ABSENT pre-GO', 'THIN', 'AUTO/JUDGE', 'PRE', 'TOO-MUCH', NULL, NULL, 'TOO-MUCH - team admin / billing / settings pre-GO = over-build flag.', 3),
  ('1', 'Explanatory header (what/do/why) + empty states', 'PS §5', 'NAIVE/JUDGE', 'IN', 'WEIGHTED', 'Med', NULL, 'Empty states matter; header sells the concept on landing.', 4),
  ('2', 'Responsive 375 + 1440, no h-scroll, thumb', 'PS §1', 'NAIVE/AUTO', 'IN', 'HARD', NULL, NULL, 'HARD - mobile-broken at 375 fails the naive-tester test outright.', 5),
  ('3', 'Touch >=44px, text >=16px, tables mobile strategy', 'PS §1', 'NAIVE', 'IN', 'WEIGHTED', 'High', NULL, 'Mobile-first portfolio - thumb-reachable is core DNA, lean HIGH.', 6),
  ('4', 'Nav collapses to drawer/hamburger on mobile', 'PS §1', 'NAIVE', 'IN', 'WEIGHTED', 'Med', NULL, 'Drawer/hamburger - common pattern, weight medium.', 7),
  ('5', 'Landing page sells the concept', 'THIN §3', 'NAIVE/JUDGE', 'IN', 'WEIGHTED', 'High', NULL, 'Landing-sells = the "I want that" before login. HIGH for distributor-led GTM.', 8),
  ('6', 'Emotional register matches product (not dull shell)', 'PS §9', 'NAIVE/JUDGE', 'IN', 'WEIGHTED', 'High', NULL, 'Dull-shell failure is the Singify lesson - HIGH; emotional register is the moat.', 9),
  ('7', 'Browser <title> = product name (not ''Create Next App'')', 'PS §7', 'AUTO', 'IN', 'HARD', NULL, NULL, 'HARD - default Next.js title is the most preventable trust-killer.', 10),
  ('8', 'OG image + manifest favicon', 'PS §7', 'AUTO', 'SCALE', 'DEFER', NULL, NULL, 'DEFER - polish; do post-Gate-2.', 11),
  ('9', 'PROMISE ATTRIBUTES present AND at quality bar', 'THIN §2/§3', 'JUDGE', 'IN-core', 'WEIGHTED', 'High', NULL, 'THE central check - this is the THIN MVP test. HIGH.', 12),
  ('10', 'Voice agent reachable from chrome <=3 clicks', 'PS §6', 'VOICE/NAIVE', 'IN', 'CONDITIONAL-HARD', NULL, 'voice', 'CONDITIONAL-HARD - portfolio voice DNA; if voiced, must be reachable.', 13),
  ('11', 'Voice consumes @caistech/elevenlabs-convai + /react, BYOK, persona', 'PS §6', 'VOICE/grep', 'COND', 'CONDITIONAL-HARD', NULL, 'voice', 'CONDITIONAL-HARD - @caistech-first; BYOK is the distribution model.', 14),
  ('12', 'Voice proactive + stage-aware', 'PS §6', 'VOICE live', 'IN', 'WEIGHTED', 'High', NULL, 'Stage-aware = the proactive moment; HIGH where voice exists.', 15),
  ('13', 'Voice placement: every Required surface voiced', 'voice-auditor', 'VOICE', 'IN/COND', 'CONDITIONAL-HARD', NULL, 'voice', 'CONDITIONAL-HARD - voice-auditor is the codified test.', 16),
  ('14', 'Voice memory loop WORKS (welcome-back recall fires, observable)', 'VMS 1-2,13,16', 'VOICE behavioural', 'IN', 'CONDITIONAL-HARD', NULL, 'voice', 'CONDITIONAL-HARD - welcome-back recall is the memory promise landing.', 17),
  ('15', 'Memory: pull-not-push, distil-then-recall, works off results', 'VMS 3-6', 'grep/JUDGE', 'COND', 'CONDITIONAL-WEIGHTED', 'High', 'voice', 'Pull-not-push pattern is core IP - HIGH where memory is in scope.', 18),
  ('16', 'Identity server-derived (conversation_id, never user_id)', 'VMS 9', 'grep', 'SEC', 'CONDITIONAL-HARD', NULL, 'voice', 'CONDITIONAL-HARD (SEC) - identity confusion = data leakage.', 19),
  ('17', 'Every convai webhook verifies HMAC (.trim), unverified->401', 'VMS 10/PS §6', 'grep/AUTO', 'SEC', 'CONDITIONAL-HARD', NULL, 'voice', 'CONDITIONAL-HARD (SEC) - unverified webhook = pwned.', 20),
  ('18', 'Allowlist on every public agent', 'VMS 18/PS §6', 'AUTO getAgent', 'SEC', 'CONDITIONAL-HARD', NULL, 'voice', 'CONDITIONAL-HARD (SEC) - public agent = abused agent without allowlist.', 21),
  ('19', 'Workspace-bind webhook (not deprecated per-agent shape)', 'VMS 18/PS §6', 'grep/AUTO', 'SEC', 'CONDITIONAL-HARD', NULL, 'voice', 'CONDITIONAL-HARD (SEC) - deprecated shape silently breaks.', 22),
  ('20', 'Cross-session authed-only; pre-auth = founder-hardcoded user_id', 'VMS 11', 'grep', 'COND', 'CONDITIONAL-WEIGHTED', 'Med', 'voice', 'Founder-hardcoded id pre-auth is fine; promote later.', 23),
  ('21', 'Memory owned/deletable/TTL + user memory surface', 'VMS 12', 'JUDGE', 'SCALE', 'DEFER', NULL, NULL, 'DEFER - GDPR-style surface; post-Gate-2.', 24),
  ('22', 'Forgot-password link + working reset flow', 'PS §2', 'NAIVE/AUTO', 'COND', 'CONDITIONAL-HARD', NULL, 'auth', 'CONDITIONAL-HARD - missing reset = blocked user, blocked outreach.', 25),
  ('23', 'Password visibility toggle (shared component)', 'PS §2', 'NAIVE', 'COND', 'CONDITIONAL-HARD', NULL, 'auth', 'CONDITIONAL-HARD - basic UX; ship shared component.', 26),
  ('24', 'Working magic-link', 'PS §2', 'NAIVE', 'COND', 'CONDITIONAL-HARD', NULL, 'auth', 'CONDITIONAL-HARD - magic-link is the friction-free path.', 27),
  ('25', 'Auth smoke-test: signup/login/reset/magic-link execute', 'PS §3', 'AUTO/NAIVE', 'COND', 'CONDITIONAL-HARD', NULL, 'auth', 'CONDITIONAL-HARD - the smoke test = the auth gate.', 28),
  ('26', 'Persistent left navbar on authed routes + active indicator', 'PS §4', 'NAIVE', 'IN', 'WEIGHTED', 'Med', NULL, 'Active indicator = orientation; medium weight.', 29),
  ('27', '/settings Profile/Password/Notifications/Account', 'PS §4', 'NAIVE', 'SCALE', 'DEFER', NULL, NULL, 'DEFER - full settings surface post-Gate-2.', 30),
  ('28', 'profiles table + on_auth_user_created + RLS', 'PS §4', 'grep/SQL', 'SCALE', 'DEFER', NULL, NULL, 'DEFER - data layer can lag; trigger on first auth product.', 31),
  ('29', 'Sign Out present', 'PS §4', 'NAIVE', 'IN', 'CONDITIONAL-WEIGHTED', 'Med', 'auth', 'Sign Out absence is a tell - medium weight where auth exists.', 32),
  ('30', 'Team admin: orgs/members/roles/invite/usage, /admin', 'PS §8', 'grep/SQL', 'SCALE', 'DEFER', NULL, NULL, 'DEFER - team admin = TOO-MUCH pre-GO; aligns with P4.', 33),
  ('31', 'Consequence clarity on irreversible/cost/outreach + confirm', 'PS §0/§9', 'NAIVE', 'IN', 'WEIGHTED', 'High', NULL, 'Irreversible/cost/outreach without confirm = trust-killer. HIGH.', 34),
  ('32', 'Zero dead ends — every screen makes next action obvious', 'PS §9', 'NAIVE', 'IN', 'WEIGHTED', 'High', NULL, 'Dead ends = exit signal. HIGH for naive-tester pass.', 35),
  ('33', 'Content/IP acknowledgment (/terms + gate) where 3rd-party IP', 'PS §9', 'NAIVE', 'IN', 'CONDITIONAL-HARD', NULL, 'third-party-content', 'CONDITIONAL-HARD - IP acknowledgment where third-party content exists.', 36),
  ('34', 'Address->Mapbox; company/ABN->ABN lookup', 'PS §9', 'NAIVE', 'COND', 'CONDITIONAL-WEIGHTED', 'Med', 'address-or-abn-fields', 'Mapbox + ABN lookups are the AU-context expectation. Medium.', 37),
  ('35', 'Email sender = updates.corporateaisolutions.com', 'PS §9', 'grep', 'SEC', 'CONDITIONAL-WEIGHTED', 'Med', 'email', 'Sender domain consistency = inbox placement; medium weight.', 38),
  ('36', '@caistech-first (fork-check clean)', 'PS §9', 'AUTO', 'SEC', 'WEIGHTED', 'High', NULL, '@caistech-first compounds across portfolio. HIGH.', 39),
  ('37', 'Feature pre-flight manifest + preflight run', 'PS §9', 'AUTO', 'PRE', 'WEIGHTED', 'High', NULL, 'Preflight = the gate orchestrator; HIGH for build discipline.', 40),
  ('38', 'Supabase: idempotent migrations via CLI, RLS every table, no client service-key', 'PS §9', 'grep/SQL', 'SEC', 'CONDITIONAL-HARD', NULL, 'supabase', 'CONDITIONAL-HARD (SEC) - RLS + no client service-key is non-negotiable.', 41),
  ('39', 'No secrets in committed files / logs', 'PS §9', 'AUTO', 'SEC', 'HARD', NULL, NULL, 'HARD (SEC) - secret leak = portfolio-wide breach risk.', 42),
  ('40', 'Vercel env vars sensitive, prod+preview only', 'PS §9', 'AUTO', 'SEC', 'HARD', NULL, NULL, 'HARD (SEC) - env hygiene; Vercel default exposes too easily.', 43),
  ('41', 'Human walkthrough: friction/terminology/''I want that''', 'naive-tester', 'NAIVE', 'IN', 'WEIGHTED', 'High', NULL, 'Naive-tester walkthrough = the codified "I want that" check. HIGH.', 44),
  ('42', 'Agent-discoverable: llms.txt + schema.org/JSON-LD + /.well-known agent manifest', 'PS §11', 'AUTO', 'COND', 'CONDITIONAL-WEIGHTED', 'Med', 'public-web', 'CONDITIONAL-WEIGHTED (public-web) - agent-era discoverability after Google I/O 2026 (WebMCP + Information Agents auto-browse). Applies where a public web surface exists: llms.txt + schema.org/JSON-LD + /.well-known agent manifest so AI search/agents find + correctly describe the product. Operability (key actions as WebMCP tools) defers to Tier-1 (post-Gate-2); cross-agent integration feeds the BizModel §5 D3 distribution-leverage score.', 45)
